solution_code:
#include <iostream>

template <typename T>
T maxOf(T a, T b)
{
    return (a > b) ? a : b;
}

class Score
{
    int m_value{};
public:
    Score(int v) : m_value{v} {}

    bool operator>(const Score& rhs) const
    {
        return m_value > rhs.m_value;
    }

    friend std::ostream& operator<<(std::ostream& out, const Score& s)
    {
        out << s.m_value;
        return out;
    }
};

int main()
{
    int a{};
    int b{};
    std::cin >> a >> b;

    std::cout << maxOf(Score{a}, Score{b}) << '\n';

    return 0;
}

